import{_ as e,c as s,o as i,ae as t}from"./chunks/framework.z0sZ1NT9.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"articles/practice/八股/webpack.md","filePath":"articles/practice/八股/webpack.md"}'),p={name:"articles/practice/八股/webpack.md"};function n(r,a,l,c,o,k){return i(),s("div",null,a[0]||(a[0]=[t(`<h2 id="webpack的目的" tabindex="-1">webpack的目的 <a class="header-anchor" href="#webpack的目的" aria-label="Permalink to &quot;webpack的目的&quot;">​</a></h2><p>早期的前端开发中，开发者需要手动引入每个JavaScript文件和CSS文件，这在项目规模较大时会变得非常麻烦和容易出错。webpack的出现解决了这个问题，它是一个模块打包工具，可以将项目中的各种资源（JavaScript、CSS、图片等）视为模块，并根据依赖关系将它们打包成一个或多个文件，从而简化了资源管理和加载过程。且可以适配不同的语法（React,Vue,TS,ES6+）,并对代码进行优化（如Tree Shaking、Code Splitting等），提升性能。</p><h2 id="webpack打包流程" tabindex="-1">webpack打包流程 <a class="header-anchor" href="#webpack打包流程" aria-label="Permalink to &quot;webpack打包流程&quot;">​</a></h2><ol><li><strong>入口（Entry）</strong>：webpack从一个或多个入口文件开始构建依赖图，默认是<code>src/index.js</code>。</li><li><strong>模块解析（Module Resolution）</strong>：webpack根据入口文件分析依赖关系，递归地解析所有依赖的模块。</li><li><strong>加载器（Loaders）</strong>：webpack使用加载器来处理非JavaScript文件（如CSS、图片等），将它们转换为JavaScript模块。</li><li><strong>插件（Plugins）</strong>：webpack使用插件来执行更广泛的任务，如优化打包结果、管理资源等。</li><li><strong>输出（Output）</strong>：webpack将打包后的文件输出到指定的目录，默认是<code>dist</code>。</li></ol><h3 id="_1-入口" tabindex="-1">1.入口 <a class="header-anchor" href="#_1-入口" aria-label="Permalink to &quot;1.入口&quot;">​</a></h3><p>一般配置在webpack.config.js中，指定入口文件路径，如：</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exports</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  entry: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./src/index.js&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div><p>webpack会从这个入口文件开始，分析其依赖关系，构建出一个依赖图（有向无环图）。解析文件中的import语句，找到所有依赖的模块，使用loader，再继续解析这些模块的依赖，直到没有新的依赖为止。</p><h3 id="_2-模块解析" tabindex="-1">2.模块解析 <a class="header-anchor" href="#_2-模块解析" aria-label="Permalink to &quot;2.模块解析&quot;">​</a></h3><p>webpack会根据入口文件分析依赖关系，递归地解析所有依赖的模块。对于每个模块，webpack会将其转换为一个JavaScript模块，并将其添加到依赖图中。对于不同的模块（本地模块、第三方模块等），webpack会采用不同的解析策略。如果是本地模块，webpack会根据相对路径解析；如果是第三方模块，webpack会根据模块名称在<code>node_modules</code>目录中查找（找到文件的index.js）。</p><h3 id="_3-加载器" tabindex="-1">3.加载器 <a class="header-anchor" href="#_3-加载器" aria-label="Permalink to &quot;3.加载器&quot;">​</a></h3><p>确定模块路径并读取文件内容后，webpack 会根据配置的 loader 规则对对应文件进行编译转换，例如通过 babel-loader 处理 JSX、ES6+ 语法，通过 css-loader 处理样式文件，将各类资源统一转为 webpack 可处理的 JS 模块。在所有模块递归解析、编译完成并形成完整依赖图之后，webpack 会根据代码分割策略（如 splitChunks）对模块进行分组，将业务代码、第三方依赖、异步路由等拆分为不同的 chunk，再经过优化（如 Tree Shaking、代码压缩），最终封装成浏览器可运行的资源并输出到指定目录。</p>`,12)]))}const b=e(p,[["render",n]]);export{d as __pageData,b as default};
